import React, { useEffect, useState } from 'react';
import { db } from '../firebase';
import { collection, query, where, orderBy, getDocs } from 'firebase/firestore';

function History({ user }) {
  const [records, setRecords] = useState([]);

  useEffect(() => {
    const fetchHistory = async () => {
      const q = query(
        collection(db, 'attendance'),
        where('userId', '==', user.uid),
        orderBy('timestamp', 'desc')
      );
      const querySnapshot = await getDocs(q);
      const data = querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
      setRecords(data);
    };
    fetchHistory();
  }, [user]);

  const groupedRecords = Object.values(
    records.reduce((acc, record) => {
      const dateKey = record.date ||
        (record.timestamp?.seconds
          ? new Date(record.timestamp.seconds * 1000).toLocaleDateString('id-ID')
          : 'Unknown date');
      const timestampSeconds = record.timestamp?.seconds || 0;

      if (!acc[dateKey]) {
        acc[dateKey] = { date: dateKey, entries: [], sortKey: timestampSeconds };
      }
      acc[dateKey].entries.push(record);
      acc[dateKey].sortKey = Math.max(acc[dateKey].sortKey, timestampSeconds);
      return acc;
    }, {})
  ).sort((a, b) => b.sortKey - a.sortKey);

  return (
    <div>
      <h2>Riwayat Absensi</h2>
      {groupedRecords.map(group => (
        <div key={group.date} className="history-item">
          <div className="hist-top">
            <span>{group.date}</span>
            <span>{group.entries.length} action(s)</span>
          </div>
          {group.entries.map(entry => (
            <div key={entry.id} className="history-entry">
              <div className="entry-info">
                <span>{entry.action}</span>
                <span>{new Date(entry.timestamp.seconds * 1000).toLocaleTimeString('id-ID')}</span>
              </div>
              <div className="hist-photos">
                <img src={entry.photo} alt={`Attendance photo ${entry.action}`} className="thumb-absen" />
              </div>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

export default History;
